              externalId: "project-missing",
            },
          ],
        });
        adapter.applyGitHubSync({
          connectionStatus: "connected",
          installationId: "gh-1",
          owner: "Ahnd6474",
          repository: "experiment",
          records: [
            {
              id: "github-project-hub",
              entityType: "project",
              entityId: createdProject.id,
              externalId: "repo-1",
              externalKey: "Ahnd6474/experiment#client-hub",
